class Solution:
    def reformatDate(self, date: str) -> str:
        month_map = {
            "Jan": 1, "Feb": 2, "Mar": 3, "Apr": 4, "May": 5, "Jun": 6,
            "Jul": 7, "Aug": 8, "Sep": 9, "Oct": 10, "Nov": 11, "Dec": 12,
        }
        parts = date.split(" ")
        day_part, month_part, year_part = parts[0], parts[1], parts[2]
        digits = ""
        for ch in day_part:
            if ch.isdigit():
                digits += ch
        day_num = int(digits)
        month_num = month_map[month_part]
        return "{}-{}-{}".format(year_part, str(month_num).zfill(2), str(day_num).zfill(2))

