class Solution:
    def reformatDate(self, date: str) -> str:
        months = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"]
        day_str, month_str, year_str = date.split()
        day = int(day_str[:-2])
        month = months.index(month_str) + 1
        return "{}-{:02d}-{:02d}".format(year_str, month, day)

